"use client";

import { useLayoutEffect } from 'react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

export function GlobalScrollEffects() {
  useLayoutEffect(() => {
    // 1. Background Color Morphing
    // We target the main container or body to transition colors smoothly
    const sections = document.querySelectorAll('section, .learning-journey-container');
    
    sections.forEach((section, i) => {
      const bgColor = section.getAttribute('data-bg-color') || 'transparent';
      if (bgColor === 'transparent') return;

      ScrollTrigger.create({
        trigger: section,
        start: "top 50%",
        end: "bottom 50%",
        onEnter: () => gsap.to('body', { backgroundColor: bgColor, duration: 1, ease: 'power2.inOut' }),
        onEnterBack: () => gsap.to('body', { backgroundColor: bgColor, duration: 1, ease: 'power2.inOut' }),
      });
    });

    return () => {
      ScrollTrigger.getAll().forEach(t => t.kill());
    };
  }, []);

  return null;
}
